  1	import * as React from 'react';
  2	import { IRow, ISortBy, OnSort, SortByDirection, TableVariant } from '@patternfly/react-table';
  3	import { ZtunnelEndpoint, ZtunnelService } from '../../types/IstioObjects';
  4	import { SimpleTable } from '../Table/SimpleTable';
  5	import { EmptyState, EmptyStateBody, EmptyStateVariant } from '@patternfly/react-core';
  6	import { kialiStyle } from '../../styles/StyleUtils';
  7	import { t } from 'i18next';
  8	import { SortableCompareTh, stickyThead, yoverflow } from './ZtunnelConfig';
  9	
 10	type ZtunnelServicesProps = {
 11	  config?: ZtunnelService[];
 12	};
 13	
 14	export const emtpytStyle = kialiStyle({
 15	  padding: 0,
 16	  margin: 0
 17	});
 18	
 19	const columns: SortableCompareTh<ZtunnelService>[] = [
 20	  {
 21	    title: t('Namespace'),
 22	    sortable: true,
 23	    compare: (a, b) => a.namespace.localeCompare(b.namespace)
 24	  },
 25	  {
 26	    title: t('Service Name'),
 27	    sortable: true,
 28	    compare: (a, b) => a.name.localeCompare(b.name)
 29	  },
 30	  {
 31	    title: t('Service VIP'),
 32	    sortable: false
 33	  },
 34	  {
 35	    title: t('Waypoint'),
 36	    sortable: true,
 37	    compare: (a, b) => a.waypoint.destination.localeCompare(b.waypoint.destination)
 38	  },
 39	  {
 40	    title: t('Endpoints'),
 41	    sortable: false
 42	  }
 43	];
 44	
 45	export const ZtunnelServicesTable: React.FC<ZtunnelServicesProps> = (props: ZtunnelServicesProps) => {
 46	  const [sortBy, setSortBy] = React.useState(0);
 47	  const [sortDirection, setSortDirection] = React.useState(SortByDirection.asc);
 48	
 49	  const getEndpoints = (endpoints: Record<string, ZtunnelEndpoint>): string => {
 50	    let total = 0;
 51	    let up = 0;
 52	    Object.entries(endpoints).forEach(([_, endpoint]) => {
 53	      total++;
 54	      if (endpoint.status === 'Healthy') {
 55	        up++;
 56	      }
 57	      return;
 58	    });
 59	    return `${total}/${up}`;
 60	  };
 61	
 62	  const compare = columns[sortBy].compare;
 63	  const sorted = compare
 64	    ? props.config?.sort(sortDirection === SortByDirection.asc ? compare : (a, b) => compare(b, a))
 65	    : props.config;
 66	
 67	  const rows: IRow[] = sorted
 68	    ? sorted.map(service => {
 69	        return {
 70	          cells: [
 71	            service.namespace,
 72	            service.name,
 73	            service.vips.map(sb => {
 74	              return sb;
 75	            }),
 76	            service.waypoint.destination ? (
 77	              <>
 78	                {service.waypoint.destination}:{service.waypoint.hboneMtlsPort}
 79	              </>
 80	            ) : (
 81	              t('None')
 82	            ),
 83	            getEndpoints(service.endpoints)
 84	          ]
 85	        };
 86	      })
 87	    : [];
 88	
 89	  const sort: ISortBy = { index: sortBy, direction: sortDirection };
 90	  const onSort: OnSort = (_event: React.MouseEvent, index: number, sortDirection: SortByDirection) => {
 91	    setSortBy(index);
 92	    setSortDirection(sortDirection);
 93	  };
 94	
 95	  const noServicesConfig: React.ReactNode = (
 96	    <EmptyState variant={EmptyStateVariant.sm} className={emtpytStyle}>
 97	      <EmptyStateBody className={emtpytStyle} data-test="istio-config-empty">
 98	        {t('No Ztunnel services found')}
 99	      </EmptyStateBody>
100	    </EmptyState>
101	  );
102	
103	  return (
104	    <div className={yoverflow}>
105	      <SimpleTable
106	        label={t('Ztunnel services config')}
107	        columns={columns}
108	        rows={rows}
109	        variant={TableVariant.compact}
110	        emptyState={noServicesConfig}
111	        sortBy={sort}
112	        onSort={onSort}
113	        theadStyle={stickyThead}
114	      />
115	    </div>
116	  );
117	};

